+import type { SmsNotificationService } from './sms-notification.service.js';
+import type { WebhookNotificationService } from './webhook-notification.service.js';
+import { Logger } from '../utils/logger.js';
+
+export type NotificationPriority = 'urgent' | 'normal' | 'low';
+
+export interface PriorityNotification {
+  priority: NotificationPriority;
+  recipient: string;
+  subject: string;
+  body: string;
+  eventType?: string;
+  payload?: Record<string, unknown>;
+}
+
+export interface RouteResult {
+  channel: 'sms' | 'email' | 'webhook';
+  priority: NotificationPriority;
+  recipient: string;
+}
+
+export class PriorityRouter {
+  private logger = new Logger('PriorityRouter');
+  private routeLog: RouteResult[] = [];
+
+  constructor(
+    private emailService: NotificationService,
+    private smsService: SmsNotificationService,
+    private webhookService: WebhookNotificationService,
+  ) {}
+
+  route(notification: PriorityNotification): RouteResult {
+    const result = this.resolveRoute(notification);
+    this.routeLog.push(result);
+    return result;
+  }
+
+  private resolveRoute(notification: PriorityNotification): RouteResult {
+    switch (notification.priority) {
+      case 'urgent':
+        return this.routeToSms(notification);
+      case 'normal':
+        return this.routeToEmail(notification);
+      case 'low':
+        return this.routeToWebhook(notification);
+    }
+  }
+
+  private routeToSms(notification: PriorityNotification): RouteResult {
+    this.logger.info(`Routing urgent notification to SMS for ${notification.recipient}`);
+    this.smsService.sendDirect({
+      phoneNumber: notification.recipient,
+      body: `[URGENT] ${notification.subject}: ${notification.body}`,
+    });
+    return { channel: 'sms', priority: 'urgent', recipient: notification.recipient };
+  }
+
+  private routeToEmail(notification: PriorityNotification): RouteResult {
+    this.logger.info(`Routing normal notification to email for ${notification.recipient}`);
+    this.emailService.sendDirect({
+      recipient: notification.recipient,
+      subject: notification.subject,
+      body: notification.body,
+    });
+    return { channel: 'email', priority: 'normal', recipient: notification.recipient };
+  }
+
+  private routeToWebhook(notification: PriorityNotification): RouteResult {
+    this.logger.info(`Routing low-priority notification to webhook for ${notification.recipient}`);
+    this.webhookService.deliverDirect(
+      notification.eventType ?? 'notification',
+      notification.payload ?? {
+        recipient: notification.recipient,
+        subject: notification.subject,
+        body: notification.body,
+      },
+    );
+    return { channel: 'webhook', priority: 'low', recipient: notification.recipient };
+  }
+
+  getRouteLog(): RouteResult[] {
+    return [...this.routeLog];
+  }
+
+  clearRouteLog(): void {
+    this.routeLog = [];
+  }
+}

