import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { SmsNotificationService, resetSmsIdCounter } from '../../src/services/sms-notification.service.js';
import { WebhookNotificationService, resetWebhookIdCounter } from '../../src/services/webhook-notification.service.js';
import { PriorityRouter } from '../../src/services/priority-router.js';
import type { PriorityNotification } from '../../src/services/priority-router.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';

describe('PriorityRouter', () => {
  let eventBus: EventBus;
  let emailService: NotificationService;
  let smsService: SmsNotificationService;
  let webhookService: WebhookNotificationService;
  let router: PriorityRouter;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    emailService = new NotificationService(eventBus);
    smsService = new SmsNotificationService(eventBus);
    webhookService = new WebhookNotificationService(eventBus, 'https://hooks.example.com/notify');
    router = new PriorityRouter(emailService, smsService, webhookService);
    resetNotificationIdCounter();
    resetSmsIdCounter();
    resetWebhookIdCounter();
  });

  describe('urgent priority routing', () => {
    it('should route urgent notifications to SMS', () => {
      const notification: PriorityNotification = {
        priority: 'urgent',
        recipient: '+1234567890',
        subject: 'Server Down',
        body: 'Production server is unresponsive',
      };

      const result = router.route(notification);

      expect(result.channel).toBe('sms');
      expect(result.priority).toBe('urgent');
      expect(result.recipient).toBe('+1234567890');
      expect(smsService.getMessageCount()).toBe(1);
      expect(smsService.getMessages()[0]?.body).toContain('[URGENT]');
      expect(smsService.getMessages()[0]?.body).toContain('Server Down');
    });

    it('should not send to email or webhook for urgent', () => {
      router.route({
        priority: 'urgent',
        recipient: '+1234567890',
        subject: 'Alert',
        body: 'Critical issue',
      });

      expect(emailService.getNotificationCount()).toBe(0);
      expect(webhookService.getDeliveryCount()).toBe(0);
    });
  });

  describe('normal priority routing', () => {
    it('should route normal notifications to email', () => {
      const notification: PriorityNotification = {
        priority: 'normal',
        recipient: 'user@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      };

      const result = router.route(notification);

      expect(result.channel).toBe('email');
      expect(result.priority).toBe('normal');
      expect(result.recipient).toBe('user@example.com');
      expect(emailService.getNotificationCount()).toBe(1);
      expect(emailService.getNotifications()[0]?.subject).toBe('Order Confirmation');
    });

    it('should not send to SMS or webhook for normal', () => {
      router.route({
        priority: 'normal',
        recipient: 'user@example.com',
        subject: 'Update',
        body: 'Info',
      });

      expect(smsService.getMessageCount()).toBe(0);
      expect(webhookService.getDeliveryCount()).toBe(0);
    });
  });

  describe('low priority routing', () => {
    it('should route low-priority notifications to webhook', () => {
      const notification: PriorityNotification = {
        priority: 'low',
        recipient: 'system',
        subject: 'Weekly Summary',
        body: 'All systems operational.',
        eventType: 'weekly-summary',
        payload: { status: 'ok', uptime: '99.9%' },
      };

      const result = router.route(notification);

      expect(result.channel).toBe('webhook');
      expect(result.priority).toBe('low');
      expect(webhookService.getDeliveryCount()).toBe(1);
      expect(webhookService.getDeliveries()[0]?.eventType).toBe('weekly-summary');
      expect(webhookService.getDeliveries()[0]?.payload).toEqual({ status: 'ok', uptime: '99.9%' });
    });

    it('should use default payload when none provided', () => {
      router.route({
        priority: 'low',
        recipient: 'system',
        subject: 'Log Entry',
        body: 'Minor event occurred',
      });

      expect(webhookService.getDeliveryCount()).toBe(1);
      const delivery = webhookService.getDeliveries()[0];
      expect(delivery?.eventType).toBe('notification');
      expect(delivery?.payload).toEqual({
        recipient: 'system',
        subject: 'Log Entry',
        body: 'Minor event occurred',
      });
    });

    it('should not send to SMS or email for low', () => {
      router.route({
        priority: 'low',
        recipient: 'system',
        subject: 'Log',
        body: 'Info',
      });

      expect(smsService.getMessageCount()).toBe(0);
      expect(emailService.getNotificationCount()).toBe(0);
    });
  });

  describe('route log', () => {
    it('should track all routed notifications', () => {
      router.route({ priority: 'urgent', recipient: 'a', subject: 's', body: 'b' });
      router.route({ priority: 'normal', recipient: 'b', subject: 's', body: 'b' });
      router.route({ priority: 'low', recipient: 'c', subject: 's', body: 'b' });

      const log = router.getRouteLog();
      expect(log).toHaveLength(3);
      expect(log[0]?.channel).toBe('sms');
      expect(log[1]?.channel).toBe('email');
      expect(log[2]?.channel).toBe('webhook');
    });

    it('should clear route log', () => {
      router.route({ priority: 'urgent', recipient: 'a', subject: 's', body: 'b' });
      router.clearRouteLog();
      expect(router.getRouteLog()).toHaveLength(0);
    });
  });

  describe('multiple notifications', () => {
    it('should route mixed priorities to correct channels', () => {
      router.route({ priority: 'urgent', recipient: 'phone1', subject: 'Alert 1', body: 'Critical' });
      router.route({ priority: 'urgent', recipient: 'phone2', subject: 'Alert 2', body: 'Critical' });
      router.route({ priority: 'normal', recipient: 'email1@test.com', subject: 'Info', body: 'Update' });
      router.route({ priority: 'low', recipient: 'system', subject: 'Log', body: 'Minor' });

      expect(smsService.getMessageCount()).toBe(2);
      expect(emailService.getNotificationCount()).toBe(1);
      expect(webhookService.getDeliveryCount()).toBe(1);
    });
  });
});
